import { CommonModule } from '@angular/common';
import { Component } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { Observable } from 'rxjs';
import { AuthService } from '../services/auth.service';
import { CartService } from '../services/cart.service';
import { CartState } from '../models';

@Component({
  selector: 'app-cart-page',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  template: `
    <section class="hero">
      <h1>Tu carrito</h1>
      <p>Revisa los productos, el envío y el cupón antes de continuar.</p>
    </section>

    <section *ngIf="cart$ | async as cart" class="detail">
      <div class="detail__panel">
        <div *ngIf="error$ | async as errorMsg">
          <div *ngIf="errorMsg" class="error" style="margin-bottom:1rem;">{{ errorMsg }}</div>
        </div>

        <div class="card" style="margin-bottom:1rem;">
          Compra protegida. Recibe el producto que necesitabas o te devolvemos el dinero.
        </div>

        <div *ngIf="auth.isAuthenticated && cartService.hasLocalCart()" class="card" style="margin-bottom:1rem;">
          Tienes un carrito local guardado en este navegador.
          <button class="back-link" type="button" style="margin-left:.5rem;" (click)="importCart()">Importar a mi cuenta</button>
        </div>

        <div class="card" style="margin-bottom:1rem;">
          <label class="block text-sm font-medium mb-1">Cupón</label>
          <div style="display:flex; gap:.5rem; flex-wrap:wrap;">
            <input [(ngModel)]="couponCode" name="couponCode" class="border rounded px-3 py-2 flex-1" placeholder="Ingresa tu cupón" />
            <button type="button" class="back-link" (click)="applyCoupon()">Aplicar</button>
          </div>
          <p *ngIf="cart.cupon" style="margin-top:.5rem;">Cupón aplicado: {{ cart.cupon.codigo }}</p>
        </div>

        <div *ngIf="cart.items.length === 0" class="empty">Tu carrito está vacío.</div>

        <div *ngFor="let item of cart.items" class="card" style="margin-bottom:1rem;">
          <h3 class="card__title">{{ getProductName(item.producto) }}</h3>
          <p class="card__meta">S/ {{ item.producto.precio_descuento | number:'1.2-2' }}</p>
          <p class="card__meta">Envío: {{ shippingLabel(item.subtotalEnvio) }}</p>
          <div style="display:flex; gap:.5rem; align-items:center; flex-wrap:wrap;">
            <button class="back-link" type="button" (click)="decrease(item.productoId)" [disabled]="item.cantidad <= 1">-</button>
            <span>{{ item.cantidad }}</span>
            <button class="back-link" type="button" (click)="increase(item.productoId)">+</button>
            <button class="trash-btn" type="button" (click)="remove(item.productoId)" title="Eliminar">
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <polyline points="3 6 5 6 21 6"></polyline>
                <path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path>
              </svg>
            </button>
          </div>
        </div>
      </div>

      <aside class="detail__panel">
        <p><strong>Productos:</strong> S/ {{ cart.subtotalProductos | number:'1.2-2' }}</p>
        <p><strong>Envíos:</strong> {{ shippingLabel(cart.subtotalEnvios) }}</p>
        <p><strong>Descuento cupón:</strong> -S/ {{ cart.descuentoCupon | number:'1.2-2' }}</p>
        <p><strong>Total:</strong> S/ {{ cart.total | number:'1.2-2' }}</p>
        <a class="back-link" routerLink="/checkout">Continuar</a>
        <p style="margin-top:1rem; color:#64748b;">El pago se conectará en una etapa posterior.</p>
      </aside>
    </section>
  `,
  styles: [`
    .trash-btn { background: none; border: none; cursor: pointer; padding: 0.5rem; color: #b91c1c; }
    .trash-btn:hover { color: #dc2626; }
  `]
})
export class CartPageComponent {
  cart$: Observable<CartState>;
  error$: Observable<string>;
  couponCode = '';

  constructor(
    public readonly cartService: CartService,
    public readonly auth: AuthService,
  ) {
    this.cart$ = this.cartService.cart$;
    this.error$ = this.cartService.error$;
    this.cartService.loadCart();
  }

  getProductName(producto: any): string {
    const marca = producto.proveedor?.nombre || '';
    return marca ? `${marca} | ${producto.nombre}` : producto.nombre;
  }

  increase(productoId: number): void {
    const item = this.cartService.snapshot.items.find((entry) => entry.productoId === productoId);
    if (item) this.cartService.updateQuantity(productoId, item.cantidad + 1);
  }

  decrease(productoId: number): void {
    const item = this.cartService.snapshot.items.find((entry) => entry.productoId === productoId);
    if (item && item.cantidad > 1) this.cartService.updateQuantity(productoId, item.cantidad - 1);
  }

  remove(productoId: number): void {
    this.cartService.removeProduct(productoId);
  }

  importCart(): void {
    this.cartService.importLocalCart();
  }

  applyCoupon(): void {
    this.cartService.applyCoupon(this.couponCode);
  }

  shippingLabel(value: number): string {
    return value > 0 ? `S/ ${value.toFixed(2)}` : 'GRATIS';
  }
}
